};

const PreferencesForm: React.FC<Props> = ({ onSubmit, onResume, savedTripDest }) => {
  const [lang, setLang] = useState<Language>('English');
  const [destInput, setDestInput] = useState('');
  const [destinations, setDestinations] = useState<string[]>([]);
  const [departFrom, setDepartFrom] = useState('');
  const [duration, setDuration] = useState('');
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [layover, setLayover] = useState('');
  const [hotel, setHotel] = useState('');
  const [selectedStyles, setSelectedStyles] = useState<string[]>([]);
  const [constraints, setConstraints] = useState('');
  const [budget, setBudget] = useState<'Economy' | 'Standard' | 'Luxury'>('Standard');
  const [pacing, setPacing] = useState<'Relaxed' | 'Balanced' | 'Intensive'>('Balanced');
  const [transportMode, setTransportMode] = useState<any>('Public Transport');

