                    value={destInput}
                    onChange={(e) => setDestInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), addDestination(destInput))}
                    placeholder={t.wherePlaceholder}
                    className="w-full pl-12 pr-4 py-4 bg-slate-50 border-0 rounded-2xl focus:ring-2 focus:ring-indigo-500/20 outline-none transition text-slate-900 font-medium placeholder:text-slate-400 shadow-inner"
                  />
                </div>
                {destinations.length > 0 && (
                  <div className="flex flex-wrap gap-2 mt-3 pl-1">
                    {destinations.map((d, i) => (
                      <span key={i} className="bg-indigo-600 text-white text-[10px] font-bold px-3 py-1.5 rounded-lg flex items-center gap-2 shadow-sm animate-scaleIn">
                        {d} <button type="button" onClick={() => removeDestination(i)}><X className="w-3 h-3" /></button>
                      </span>
                    ))}
                  </div>
                )}
